import{c as t,Q as a,j as r,m as i}from"./chunks/framework.ByJJFMw8.js";const f=JSON.parse('{"title":"Docs Home","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/index.md","filePath":"en/guide/index.md","lastUpdated":1782144392000}'),o={name:"en/guide/index.md"};function s(n,e,d,l,c,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="docs-home" tabindex="-1">Docs Home <a class="header-anchor" href="#docs-home" aria-label="Permalink to &quot;Docs Home&quot;">​</a></h1><div class="doc-kicker">Start From The Right Door</div><p class="doc-lead"> Flyfish Viewer is an offline-first frontend file preview system for web applications. It is designed for attachment centers, workflow tools, knowledge bases, support portals, and self-hosted intranet products that need broad file coverage without running a document conversion backend. </p><h2 id="what-to-read-first" tabindex="-1">What To Read First <a class="header-anchor" href="#what-to-read-first" aria-label="Permalink to &quot;What To Read First&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Goal</th><th>Page</th></tr></thead><tbody><tr><td>Run the viewer in a project</td><td><a href="/en/guide/quickstart">Quickstart</a></td></tr><tr><td>Pick the right npm package</td><td><a href="/en/guide/ecosystem">Ecosystem packages</a></td></tr><tr><td>Check format coverage</td><td><a href="/en/guide/formats">Supported formats</a></td></tr><tr><td>Understand npm, GitHub, releases, and self-hosted assets</td><td><a href="/en/guide/distribution">Distribution</a></td></tr></tbody></table><h2 id="main-links" tabindex="-1">Main Links <a class="header-anchor" href="#main-links" aria-label="Permalink to &quot;Main Links&quot;">​</a></h2><ul><li>Live demo: <a href="https://demo.file-viewer.app" target="_blank" rel="noreferrer">demo.file-viewer.app</a></li><li>Document comparison demo: <a href="https://demo.file-viewer.app/compare.html" target="_blank" rel="noreferrer">demo.file-viewer.app/compare.html</a></li><li>GitHub repository: <a href="https://github.com/flyfish-dev/file-viewer" target="_blank" rel="noreferrer">github.com/flyfish-dev/file-viewer</a></li><li>npm scope: <a href="https://www.npmjs.com/search?q=%40file-viewer" target="_blank" rel="noreferrer"><code>@file-viewer</code></a></li><li>Sponsorship and priority support: <a href="https://dev.flyfish.group/shop" target="_blank" rel="noreferrer">dev.flyfish.group/shop</a></li></ul><h2 id="positioning" tabindex="-1">Positioning <a class="header-anchor" href="#positioning" aria-label="Permalink to &quot;Positioning&quot;">​</a></h2><p>Flyfish Viewer is not trying to replace specialist editors. It gives business products a practical, embedded preview layer for common and uncommon attachments: documents, spreadsheets, slides, PDFs, archives, email, diagrams, CAD drawings, 3D assets, code, logs, media, and data files.</p><p>The project keeps a pure TypeScript core under <code>@file-viewer/core</code>, split renderer packages for heavier formats, and native component packages for Web Components, Vue, React, jQuery, and Svelte.</p>',10)])])}const m=t(o,[["render",s]]);export{f as __pageData,m as default};
